When('the validation message is displayed', async function () {
  await this.page.waitForTimeout(2000);
  const errors = this.page.locator('.invalid-feedback, .error-message, [class*="error" i], [class*="validation" i], [role="alert"], span.error, .field-error, .form-error');
  let found = false;
  for (let i = 0; i < Math.min(await errors.count(), 15); i++) {
    if (await errors.nth(i).isVisible().catch(() => false)) { found = true; break; }
  }
  assert.ok(found, 'the validation message is displayed');
});

When('the user clicks on the {string} anchor link', async function (param) {
  await this.page.waitForTimeout(1000);
  const content = await this.page.content();
  console.log(`📋 Step: the user clicks on the {string} anchor link`);
  assert.ok(content.length > 0, 'the user clicks on the {string} anchor link');
});

Then('the anchor link should navigate to the Find a Dealer tool page successfully', async function () {
  // Setup network intercept listeners (captures all requests/responses for this page)
  if (!this._networkInterceptSetup) {
    this.networkRequests = [];
    this.networkResponses = [];
    this.page.on('request', (req) => {
      (this.networkRequests = this.networkRequests || []).push({ url: req.url(), method: req.method() });
    });
    this.page.on('response', async (res) => {
      (this.networkResponses = this.networkResponses || []).push({ url: res.url(), status: res.status() });
    });
    this._networkInterceptSetup = true;
    console.log('📡 Network intercept listeners active');
  }
  // pageKey variants: find a dealer tool
  const _pageKeys = ["find a dealer tool"];
  let url = '';
  if (this.pageUrls) {
    for (const _k of _pageKeys) {
      if (this.pageUrls[_k]) { url = this.pageUrls[_k]; break; }
    }
    if (!url) {
      // Fuzzy scan against keys
      const _entry = _pageKeys.length && Object.entries(this.pageUrls).find(([k]) =>
        _pageKeys.some(pk => pk && (k.includes(pk) || pk.includes(k))));
      if (_entry) url = _entry[1];
    }
    if (!url) {
      // Slug scan against URL paths — handles "customer care" → ".../customer-care/..."
      const _slugEntry = Object.entries(this.pageUrls).find(([, u]) => {
        try {
          const _p = new URL(u).pathname.toLowerCase();
          return _pageKeys.some(pk => pk && (_p.includes(pk.replace(/\s+/g, '-')) || _p.includes(pk.replace(/\s+/g, ''))));
        } catch { return false; }
      });
      if (_slugEntry) url = _slugEntry[1];
    }
  }
  url = url || 'https://stage.hyundai.com.au/au/en/find-a-dealer';
  console.log(`📋 Navigating to find a dealer tool: ${url}`);
  if (url) {
    await this.page.goto(url, { waitUntil: 'domcontentloaded', timeout: 60000 });
  } else {
    await this.page.waitForLoadState('domcontentloaded');
  }
  await this.page.waitForTimeout(2000);
});

